import { useState } from "react";

// ─── DUMMY DATA ───────────────────────────────────────────────────────────────
const DEPARTMENTS = [
  { id: 1, name: "Computer Science & Engineering", hod: "Dr. Ravi Kumar", students: 480, faculty: 28 },
  { id: 2, name: "Electronics & Communication", hod: "Dr. Sunita Rao", students: 360, faculty: 22 },
  { id: 3, name: "Mechanical Engineering", hod: "Dr. Arjun Nair", students: 420, faculty: 25 },
  { id: 4, name: "Civil Engineering", hod: "Dr. Priya Sharma", students: 310, faculty: 19 },
  { id: 5, name: "Information Technology", hod: "Dr. Kavitha Reddy", students: 390, faculty: 21 },
  { id: 6, name: "Electrical Engineering", hod: "Dr. Mohan Das", students: 270, faculty: 17 },
  { id: 7, name: "MBA", hod: "Dr. Ananya Krishnan", students: 180, faculty: 14 },
  { id: 8, name: "MCA", hod: "Dr. Suresh Babu", students: 120, faculty: 10 },
];

const FACULTY = [
  { id: 1, name: "Dr. Ravi Kumar", dept: "CSE", email: "ravi.kumar@mallareddy.edu.in", contact: "9876543210", designation: "Professor & HOD" },
  { id: 2, name: "Dr. Sunita Rao", dept: "ECE", email: "sunita.rao@mallareddy.edu.in", contact: "9876543211", designation: "Professor & HOD" },
  { id: 3, name: "Prof. Ramesh Naidu", dept: "CSE", email: "ramesh.n@mallareddy.edu.in", contact: "9876543212", designation: "Associate Professor" },
  { id: 4, name: "Dr. Lakshmi Devi", dept: "IT", email: "lakshmi.d@mallareddy.edu.in", contact: "9876543213", designation: "Assistant Professor" },
  { id: 5, name: "Prof. Venkat Rao", dept: "MECH", email: "venkat.rao@mallareddy.edu.in", contact: "9876543214", designation: "Associate Professor" },
  { id: 6, name: "Dr. Padma Priya", dept: "CIVIL", email: "padma.p@mallareddy.edu.in", contact: "9876543215", designation: "Professor" },
  { id: 7, name: "Prof. Srinivas Reddy", dept: "EEE", email: "srinivas.r@mallareddy.edu.in", contact: "9876543216", designation: "Assistant Professor" },
  { id: 8, name: "Dr. Meena Kumari", dept: "MBA", email: "meena.k@mallareddy.edu.in", contact: "9876543217", designation: "Associate Professor" },
];

const TEACHING_STAFF = [
  { id: 1, name: "Dr. Ravi Kumar", dept: "CSE", qualification: "Ph.D", experience: "15 yrs", status: "Active" },
  { id: 2, name: "Prof. Ramesh Naidu", dept: "CSE", qualification: "M.Tech", experience: "10 yrs", status: "Active" },
  { id: 3, name: "Dr. Sunita Rao", dept: "ECE", qualification: "Ph.D", experience: "18 yrs", status: "Active" },
  { id: 4, name: "Dr. Lakshmi Devi", dept: "IT", qualification: "Ph.D", experience: "12 yrs", status: "Active" },
  { id: 5, name: "Prof. Venkat Rao", dept: "MECH", qualification: "M.E", experience: "8 yrs", status: "Active" },
];

const NON_TEACHING_STAFF = [
  { id: 1, name: "K. Murthy", role: "Lab Technician", dept: "CSE", contact: "9876540001", status: "Active" },
  { id: 2, name: "S. Lakshmi", role: "Administrative Asst.", dept: "Admin", contact: "9876540002", status: "Active" },
  { id: 3, name: "P. Raju", role: "Librarian", dept: "Library", contact: "9876540003", status: "Active" },
  { id: 4, name: "M. Devi", role: "Accountant", dept: "Finance", contact: "9876540004", status: "Active" },
  { id: 5, name: "R. Kishore", role: "Security Head", dept: "Security", contact: "9876540005", status: "Active" },
];

const TRANSPORT = [
  { id: 1, bus: "MRC-01", route: "Secunderabad → College", driver: "K. Venkatesh", contact: "9988776601", students: 45 },
  { id: 2, bus: "MRC-02", route: "Dilsukhnagar → College", driver: "M. Raju", contact: "9988776602", students: 52 },
  { id: 3, bus: "MRC-03", route: "Kukatpally → College", driver: "S. Kumar", contact: "9988776603", students: 38 },
  { id: 4, bus: "MRC-04", route: "Uppal → College", driver: "P. Naidu", contact: "9988776604", students: 41 },
  { id: 5, bus: "MRC-05", route: "LB Nagar → College", driver: "R. Reddy", contact: "9988776605", students: 49 },
  { id: 6, bus: "MRC-06", route: "Ameerpet → College", driver: "T. Rao", contact: "9988776606", students: 36 },
];

const MONTHLY_FEES = [
  { month: "Jun", collected: 18.2, pending: 3.1 },
  { month: "Jul", collected: 22.5, pending: 2.8 },
  { month: "Aug", collected: 25.1, pending: 1.9 },
  { month: "Sep", collected: 20.8, pending: 3.4 },
  { month: "Oct", collected: 24.3, pending: 2.2 },
  { month: "Nov", collected: 19.6, pending: 4.1 },
];

const INITIAL_ANNOUNCEMENTS = [
  { id: 1, title: "Semester Exams Schedule Released", date: "2025-11-10", priority: "High", message: "End semester examinations will commence from December 1st, 2025. Timetable uploaded on the portal." },
  { id: 2, title: "Annual Day Celebration", date: "2025-11-05", priority: "Medium", message: "Annual Day will be celebrated on November 25th. All students and faculty are requested to participate." },
  { id: 3, title: "Fee Payment Deadline", date: "2025-11-01", priority: "High", message: "Last date for fee payment is November 20th. Late payments will attract a penalty of ₹500/day." },
  { id: 4, title: "Sports Week", date: "2025-10-28", priority: "Low", message: "Sports week will be held from November 10–15. Students can register with their respective department coordinators." },
];

// ─── STYLES ──────────────────────────────────────────────────────────────────
const CSS = `
  @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@600;700&family=DM+Sans:wght@300;400;500;600&display=swap');
  @import url('https://cdn.jsdelivr.net/npm/bootstrap@5.3.2/dist/css/bootstrap.min.css');

  :root {
    --primary: #1a3c5e;
    --primary-light: #2a5a8e;
    --primary-dark: #0f2438;
    --accent: #c8a84b;
    --accent-light: #f0d078;
    --sidebar-bg: #0f2438;
    --sidebar-text: #a8c4d8;
    --sidebar-active: #c8a84b;
    --content-bg: #f0f4f8;
    --card-bg: #ffffff;
    --text-dark: #1a2332;
    --text-muted: #6b7c93;
    --border: #dce4ed;
    --success: #2ecc71;
    --danger: #e74c3c;
    --warning: #f39c12;
    --info: #3498db;
  }

  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: 'DM Sans', sans-serif; background: var(--content-bg); }

  /* ── LOGIN ── */
  .login-page {
    min-height: 100vh;
    background: linear-gradient(135deg, #0f2438 0%, #1a3c5e 40%, #2a5a8e 100%);
    display: flex; align-items: center; justify-content: center;
    position: relative; overflow: hidden;
  }
  .login-page::before {
    content: '';
    position: absolute; inset: 0;
    background-image: radial-gradient(circle at 20% 30%, rgba(200,168,75,0.12) 0%, transparent 50%),
                      radial-gradient(circle at 80% 70%, rgba(42,90,142,0.3) 0%, transparent 50%);
  }
  .login-card {
    background: rgba(255,255,255,0.97);
    border-radius: 20px;
    padding: 0;
    overflow: hidden;
    box-shadow: 0 30px 80px rgba(0,0,0,0.35);
    max-width: 440px; width: 100%;
    position: relative; z-index: 1;
    border: 1px solid rgba(200,168,75,0.3);
  }
  .login-header {
    background: linear-gradient(135deg, #0f2438, #1a3c5e);
    padding: 36px 32px 28px;
    text-align: center;
    border-bottom: 3px solid var(--accent);
  }
  .login-logo {
    width: 76px; height: 76px;
    background: linear-gradient(135deg, var(--accent), var(--accent-light));
    border-radius: 50%;
    display: flex; align-items: center; justify-content: center;
    margin: 0 auto 16px;
    font-size: 32px; color: #0f2438;
    box-shadow: 0 8px 24px rgba(200,168,75,0.4);
    font-weight: 700;
  }
  .login-title {
    font-family: 'Playfair Display', serif;
    font-size: 1.5rem; color: #ffffff; font-weight: 700;
    margin-bottom: 4px; letter-spacing: 0.3px;
  }
  .login-subtitle { font-size: 0.82rem; color: var(--accent); letter-spacing: 1.5px; text-transform: uppercase; }
  .login-body { padding: 32px; }
  .login-welcome {
    text-align: center; margin-bottom: 24px;
  }
  .login-welcome h5 {
    font-family: 'Playfair Display', serif;
    color: var(--primary-dark); font-size: 1.15rem; margin-bottom: 4px;
  }
  .login-welcome p { font-size: 0.83rem; color: var(--text-muted); }
  .form-label { font-size: 0.82rem; font-weight: 600; color: var(--primary-dark); letter-spacing: 0.5px; text-transform: uppercase; }
  .form-control {
    border: 1.5px solid var(--border);
    border-radius: 10px; padding: 11px 14px;
    font-size: 0.9rem; transition: all 0.2s;
  }
  .form-control:focus { border-color: var(--primary-light); box-shadow: 0 0 0 3px rgba(26,60,94,0.12); }
  .btn-login {
    background: linear-gradient(135deg, var(--primary), var(--primary-light));
    color: #fff; border: none; border-radius: 10px;
    padding: 12px; font-size: 0.95rem; font-weight: 600;
    width: 100%; letter-spacing: 0.5px;
    transition: all 0.25s; cursor: pointer;
    box-shadow: 0 6px 20px rgba(26,60,94,0.35);
  }
  .btn-login:hover { transform: translateY(-2px); box-shadow: 0 10px 28px rgba(26,60,94,0.45); }
  .login-hint { font-size: 0.78rem; color: var(--text-muted); text-align: center; margin-top: 16px; }

  /* ── LAYOUT ── */
  .app-layout { display: flex; min-height: 100vh; }

  /* ── SIDEBAR ── */
  .sidebar {
    width: 260px; min-height: 100vh;
    background: var(--sidebar-bg);
    display: flex; flex-direction: column;
    position: fixed; left: 0; top: 0; bottom: 0; z-index: 100;
    transition: width 0.3s ease;
    box-shadow: 4px 0 20px rgba(0,0,0,0.25);
  }
  .sidebar-brand {
    padding: 24px 20px;
    border-bottom: 1px solid rgba(255,255,255,0.08);
    display: flex; align-items: center; gap: 12px;
  }
  .brand-logo {
    width: 44px; height: 44px; border-radius: 10px;
    background: linear-gradient(135deg, var(--accent), var(--accent-light));
    display: flex; align-items: center; justify-content: center;
    font-weight: 800; font-size: 18px; color: var(--primary-dark);
    flex-shrink: 0;
  }
  .brand-text { overflow: hidden; }
  .brand-name {
    font-family: 'Playfair Display', serif;
    font-size: 1rem; color: #fff; font-weight: 700; line-height: 1.2;
  }
  .brand-role { font-size: 0.72rem; color: var(--accent); letter-spacing: 1px; text-transform: uppercase; }

  .sidebar-nav { flex: 1; overflow-y: auto; padding: 12px 0; }
  .nav-section-label {
    font-size: 0.65rem; font-weight: 700; letter-spacing: 2px;
    text-transform: uppercase; color: rgba(168,196,216,0.45);
    padding: 16px 20px 6px; margin-top: 4px;
  }
  .nav-item {
    display: flex; align-items: center; gap: 12px;
    padding: 11px 20px; cursor: pointer;
    color: var(--sidebar-text); font-size: 0.88rem; font-weight: 400;
    transition: all 0.2s; position: relative;
    text-decoration: none; user-select: none;
    border-left: 3px solid transparent;
  }
  .nav-item:hover { background: rgba(255,255,255,0.06); color: #fff; }
  .nav-item.active {
    background: rgba(200,168,75,0.12);
    color: var(--accent); font-weight: 600;
    border-left-color: var(--accent);
  }
  .nav-item .nav-icon { font-size: 1.1rem; width: 22px; flex-shrink: 0; }

  .sidebar-footer {
    padding: 16px 20px;
    border-top: 1px solid rgba(255,255,255,0.08);
  }
  .user-chip {
    display: flex; align-items: center; gap: 10px;
    background: rgba(255,255,255,0.06); border-radius: 10px; padding: 10px 12px;
  }
  .user-avatar {
    width: 36px; height: 36px; border-radius: 50%;
    background: linear-gradient(135deg, var(--accent), var(--accent-light));
    display: flex; align-items: center; justify-content: center;
    font-weight: 700; font-size: 14px; color: var(--primary-dark); flex-shrink: 0;
  }
  .user-name { font-size: 0.82rem; color: #fff; font-weight: 600; line-height: 1.2; }
  .user-role { font-size: 0.7rem; color: var(--accent); }

  /* ── MAIN ── */
  .main-wrap { margin-left: 260px; flex: 1; display: flex; flex-direction: column; min-height: 100vh; }

  /* ── TOPBAR ── */
  .topbar {
    background: #fff; height: 64px;
    display: flex; align-items: center; justify-content: space-between;
    padding: 0 28px; position: sticky; top: 0; z-index: 50;
    border-bottom: 1px solid var(--border);
    box-shadow: 0 2px 12px rgba(0,0,0,0.06);
  }
  .topbar-left { display: flex; align-items: center; gap: 12px; }
  .page-title { font-family: 'Playfair Display', serif; font-size: 1.25rem; color: var(--primary-dark); font-weight: 700; }
  .breadcrumb-text { font-size: 0.78rem; color: var(--text-muted); }
  .topbar-right { display: flex; align-items: center; gap: 16px; }
  .topbar-btn {
    width: 38px; height: 38px; border-radius: 10px;
    background: var(--content-bg); border: 1px solid var(--border);
    display: flex; align-items: center; justify-content: center;
    cursor: pointer; color: var(--text-muted); font-size: 1rem;
    transition: all 0.2s; position: relative;
  }
  .topbar-btn:hover { background: var(--primary); color: #fff; border-color: var(--primary); }
  .notif-badge {
    position: absolute; top: -4px; right: -4px;
    background: var(--danger); color: #fff;
    width: 16px; height: 16px; border-radius: 50%;
    font-size: 0.6rem; display: flex; align-items: center; justify-content: center;
    font-weight: 700;
  }
  .date-chip {
    background: var(--content-bg); border: 1px solid var(--border);
    border-radius: 8px; padding: 6px 12px;
    font-size: 0.78rem; color: var(--text-muted); font-weight: 500;
  }
  .logout-btn {
    background: linear-gradient(135deg, var(--danger), #c0392b);
    color: #fff; border: none; border-radius: 8px;
    padding: 7px 16px; font-size: 0.8rem; font-weight: 600;
    cursor: pointer; transition: all 0.2s;
  }
  .logout-btn:hover { opacity: 0.85; }

  /* ── CONTENT ── */
  .content-area { padding: 28px; flex: 1; }

  /* ── STAT CARDS ── */
  .stat-card {
    background: var(--card-bg); border-radius: 16px;
    padding: 22px 22px 18px;
    border: 1px solid var(--border);
    box-shadow: 0 4px 16px rgba(0,0,0,0.05);
    transition: transform 0.2s, box-shadow 0.2s;
    overflow: hidden; position: relative;
  }
  .stat-card:hover { transform: translateY(-3px); box-shadow: 0 10px 28px rgba(0,0,0,0.1); }
  .stat-card::after {
    content: ''; position: absolute;
    top: 0; right: 0; width: 80px; height: 80px;
    border-radius: 0 16px 0 100%;
    opacity: 0.07;
  }
  .stat-card.c1::after { background: #3498db; }
  .stat-card.c2::after { background: #2ecc71; }
  .stat-card.c3::after { background: #9b59b6; }
  .stat-card.c4::after { background: #e67e22; }
  .stat-card.c5::after { background: #1abc9c; }
  .stat-card.c6::after { background: #e74c3c; }
  .stat-icon {
    width: 48px; height: 48px; border-radius: 12px;
    display: flex; align-items: center; justify-content: center;
    font-size: 1.4rem; margin-bottom: 14px;
  }
  .stat-value { font-family: 'Playfair Display', serif; font-size: 2rem; font-weight: 700; color: var(--text-dark); line-height: 1; margin-bottom: 4px; }
  .stat-label { font-size: 0.8rem; color: var(--text-muted); font-weight: 500; text-transform: uppercase; letter-spacing: 0.5px; }
  .stat-trend { font-size: 0.75rem; margin-top: 10px; display: flex; align-items: center; gap: 4px; }
  .trend-up { color: var(--success); }
  .trend-down { color: var(--danger); }

  /* ── SECTION CARD ── */
  .section-card {
    background: var(--card-bg); border-radius: 16px;
    padding: 24px; border: 1px solid var(--border);
    box-shadow: 0 4px 16px rgba(0,0,0,0.05); margin-bottom: 24px;
  }
  .section-title {
    font-family: 'Playfair Display', serif;
    font-size: 1.15rem; color: var(--primary-dark); font-weight: 700;
    margin-bottom: 4px;
  }
  .section-subtitle { font-size: 0.78rem; color: var(--text-muted); margin-bottom: 20px; }

  /* ── TABLES ── */
  .custom-table { font-size: 0.85rem; }
  .custom-table thead th {
    background: var(--primary-dark); color: var(--accent);
    font-size: 0.72rem; letter-spacing: 0.8px; text-transform: uppercase;
    font-weight: 600; border: none; padding: 12px 14px;
  }
  .custom-table tbody td { padding: 11px 14px; vertical-align: middle; border-color: var(--border); }
  .custom-table tbody tr:hover { background: rgba(26,60,94,0.04); }
  .badge-dept { font-size: 0.72rem; padding: 4px 10px; border-radius: 20px; font-weight: 600; }
  .badge-active { background: rgba(46,204,113,0.15); color: #27ae60; }
  .badge-high { background: rgba(231,76,60,0.15); color: #c0392b; }
  .badge-medium { background: rgba(243,156,18,0.15); color: #e67e22; }
  .badge-low { background: rgba(52,152,219,0.15); color: #2980b9; }

  /* ── CHART BAR ── */
  .chart-bar-wrap { display: flex; flex-direction: column; gap: 10px; }
  .chart-row { display: flex; align-items: center; gap: 12px; }
  .chart-month { width: 30px; font-size: 0.75rem; color: var(--text-muted); font-weight: 600; flex-shrink: 0; }
  .bar-track { flex: 1; background: var(--border); border-radius: 20px; overflow: hidden; height: 22px; position: relative; }
  .bar-fill { height: 100%; border-radius: 20px; display: flex; align-items: center; padding-left: 10px; font-size: 0.7rem; font-weight: 600; color: #fff; transition: width 0.8s ease; }
  .bar-collected { background: linear-gradient(90deg, var(--primary), var(--primary-light)); }
  .bar-pending { background: linear-gradient(90deg, #e67e22, #f39c12); }
  .chart-val { width: 50px; font-size: 0.75rem; font-weight: 600; color: var(--text-muted); text-align: right; flex-shrink: 0; }

  /* ── FEE CARDS ── */
  .fee-card {
    border-radius: 16px; padding: 24px;
    color: #fff; text-align: center;
    box-shadow: 0 8px 24px rgba(0,0,0,0.12);
  }
  .fee-card .fee-amt { font-family: 'Playfair Display', serif; font-size: 2.2rem; font-weight: 700; }
  .fee-card .fee-label { font-size: 0.8rem; opacity: 0.85; letter-spacing: 0.5px; margin-top: 4px; }

  /* ── ANNOUNCEMENTS ── */
  .annc-item {
    border-left: 3px solid var(--accent);
    background: var(--content-bg); border-radius: 0 10px 10px 0;
    padding: 14px 16px; margin-bottom: 12px;
    transition: all 0.2s;
  }
  .annc-item:hover { background: #e8eff5; }
  .annc-title { font-weight: 600; font-size: 0.9rem; color: var(--primary-dark); }
  .annc-date { font-size: 0.73rem; color: var(--text-muted); margin-top: 2px; }
  .annc-msg { font-size: 0.82rem; color: var(--text-muted); margin-top: 6px; }

  /* ── REPORTS ── */
  .report-card {
    background: var(--card-bg); border: 1px solid var(--border);
    border-radius: 16px; padding: 28px 24px; text-align: center;
    transition: all 0.25s; cursor: pointer;
    box-shadow: 0 4px 16px rgba(0,0,0,0.05);
  }
  .report-card:hover { transform: translateY(-4px); box-shadow: 0 14px 32px rgba(0,0,0,0.1); border-color: var(--primary-light); }
  .report-icon {
    width: 64px; height: 64px; border-radius: 16px;
    display: flex; align-items: center; justify-content: center;
    margin: 0 auto 16px; font-size: 1.8rem;
  }
  .report-name { font-family: 'Playfair Display', serif; font-size: 1.05rem; font-weight: 700; color: var(--primary-dark); margin-bottom: 6px; }
  .report-desc { font-size: 0.78rem; color: var(--text-muted); margin-bottom: 16px; }
  .btn-download {
    background: linear-gradient(135deg, var(--primary), var(--primary-light));
    color: #fff; border: none; border-radius: 8px;
    padding: 8px 20px; font-size: 0.82rem; font-weight: 600;
    cursor: pointer; transition: all 0.2s;
  }
  .btn-download:hover { opacity: 0.88; transform: translateY(-1px); }

  /* ── SCROLLBAR ── */
  ::-webkit-scrollbar { width: 5px; }
  ::-webkit-scrollbar-track { background: transparent; }
  ::-webkit-scrollbar-thumb { background: rgba(26,60,94,0.2); border-radius: 10px; }

  /* ── FORM ── */
  .add-annc-form { background: var(--content-bg); border-radius: 12px; padding: 20px; margin-bottom: 24px; border: 1px solid var(--border); }

  /* ── RESPONSIVE ── */
  @media (max-width: 768px) {
    .sidebar { width: 0; }
    .main-wrap { margin-left: 0; }
  }
`;

